import{_ as e,o as t,c as n,ag as s}from"./chunks/framework.KHntoz-C.js";const o="/lingua-docs/assets/logoLinguaHorizzontal.BvKknpTU.svg",u=JSON.parse('{"title":"What is Lingua?","description":"","frontmatter":{},"headers":[],"relativePath":"guide/introduction.md","filePath":"guide/introduction.md"}'),r={name:"guide/introduction.md"};function i(l,a,d,p,c,g){return t(),n("div",null,[...a[0]||(a[0]=[s('<figure style="margin:30px auto 0 !important;max-width:320px;"><img src="'+o+`" alt="Language selector in sidebar mode"></figure><h1 id="what-is-lingua" tabindex="-1">What is Lingua? <a class="header-anchor" href="#what-is-lingua" aria-label="Permalink to &quot;What is Lingua?&quot;">​</a></h1><p>Lingua is a <strong>Laravel package</strong> that replaces the default file-based translation system with a fully database-driven one, complete with a beautiful, reactive management UI built on <a href="https://livewire.laravel.com" target="_blank" rel="noreferrer">Livewire 4</a> and <a href="https://fluxui.dev" target="_blank" rel="noreferrer">Flux 2</a>.</p><h2 id="the-problem-it-solves" tabindex="-1">The problem it solves <a class="header-anchor" href="#the-problem-it-solves" aria-label="Permalink to &quot;The problem it solves&quot;">​</a></h2><p>Standard Laravel translations live in PHP and JSON files inside <code>lang/</code>. This works well for small projects, but it creates friction as an application grows:</p><ul><li><strong>Updating a translation requires a deployment</strong> — even for a simple typo fix.</li><li><strong>Non-technical team members can&#39;t edit translations</strong> — editors need Git and a code review.</li><li><strong>Tracking translation completeness is manual</strong> — you have to diff files to find gaps.</li><li><strong>Supporting many locales clutters the codebase</strong> — dozens of files scattered across directories.</li></ul><p>Lingua stores every translation in the database, in a single JSON column per row, and provides a Livewire UI where any authorised user can manage languages and strings in real time.</p><h2 id="how-it-works-at-a-glance" tabindex="-1">How it works at a glance <a class="header-anchor" href="#how-it-works-at-a-glance" aria-label="Permalink to &quot;How it works at a glance&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                   Laravel Application                   │</span></span>
<span class="line"><span>│                                                         │</span></span>
<span class="line"><span>│  lang/en/messages.php  ──┐                              │</span></span>
<span class="line"><span>│  lang/fr/messages.php    │  lingua:sync-to-database     │</span></span>
<span class="line"><span>│  lang/en.json            ├─────────────────────────────►│</span></span>
<span class="line"><span>│  lang/vendor/…           │                              │</span></span>
<span class="line"><span>│                         ─┘   language_lines (DB)        │</span></span>
<span class="line"><span>│                              ┌──────────────────────┐   │</span></span>
<span class="line"><span>│  LinguaMiddleware  ◄──────── │ group │ key │ text   │   │</span></span>
<span class="line"><span>│  app()-&gt;setLocale()          │ auth  │ … │ {&quot;en&quot;:…} │   │</span></span>
<span class="line"><span>│                              └──────────────────────┘   │</span></span>
<span class="line"><span>│  __(&#39;auth.failed&#39;)  ────────────────────────────────────►│</span></span>
<span class="line"><span>│  (DB takes precedence over files)                       │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────┘</span></span></code></pre></div><p>At runtime, Lingua registers a custom <code>LinguaManager</code> as the Laravel translation loader. It merges file-based and database translations — <strong>database entries always take precedence</strong> — so you can override any string without touching source files.</p><h2 id="key-concepts" tabindex="-1">Key concepts <a class="header-anchor" href="#key-concepts" aria-label="Permalink to &quot;Key concepts&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Concept</th><th>Description</th></tr></thead><tbody><tr><td><strong>Language</strong></td><td>An installed locale with metadata (name, native name, direction, sort order, default flag)</td></tr><tr><td><strong>Translation</strong></td><td>A row in <code>language_lines</code> with a <code>group</code>, <code>key</code>, <code>type</code>, and a JSON <code>text</code> column holding all locale values</td></tr><tr><td><strong>Translation type</strong></td><td><code>text</code>, <code>html</code>, or <code>markdown</code> — determines which editor is shown in the UI</td></tr><tr><td><strong>Vendor translation</strong></td><td>A translation that belongs to a third-party package; protected from accidental deletion</td></tr><tr><td><strong>Default locale</strong></td><td>The primary language; deleting a translation for the default locale removes the entire record</td></tr><tr><td><strong>Sync</strong></td><td>The process of importing local files → DB (<code>sync-to-database</code>) or exporting DB → files (<code>sync-to-local</code>)</td></tr></tbody></table><h2 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Dependency</th><th>Version</th></tr></thead><tbody><tr><td>PHP</td><td><strong>8.4+</strong></td></tr><tr><td>Laravel</td><td><strong>12+</strong></td></tr><tr><td>Livewire</td><td><strong>4.1+</strong></td></tr><tr><td>Livewire Flux</td><td><strong>2.12+</strong></td></tr></tbody></table><h2 id="next-step" tabindex="-1">Next step <a class="header-anchor" href="#next-step" aria-label="Permalink to &quot;Next step&quot;">​</a></h2><p>Head to the <a href="/lingua-docs/guide/installation.html">Installation guide</a> to set up Lingua in under five minutes.</p>`,16)])])}const m=e(r,[["render",i]]);export{u as __pageData,m as default};
